// Check throttle and quiet hours, format notification
const items = $input.all();
const results = [];

for (const item of items) {
  const email = item.json;
  const now = new Date();
  const ukHour = parseInt(now.toLocaleString('en-GB', { timeZone: 'Europe/London', hour: '2-digit', hour12: false }));
  const isQuietHours = ukHour >= 22 || ukHour < 7;

  // During quiet hours, only send for interview_invite and offer
  // follow_up_request can wait unless deadline < 24h
  if (isQuietHours && email.classification === 'follow_up_request') {
    const deadline = email.action_deadline ? new Date(email.action_deadline) : null;
    const hoursUntilDeadline = deadline ? (deadline.getTime() - now.getTime()) / 3600000 : 999;
    if (hoursUntilDeadline > 24) {
      // Skip during quiet hours
      continue;
    }
  }

  // Build notification subject and body
  let notifSubject = '';
  let notifBody = '';
  let notifType = '';
  const gmailLink = `https://mail.google.com/mail/u/0/#inbox/${email.gmail_message_id}`;

  switch (email.classification) {
    case 'interview_invite':
      notifType = 'interview_alert';
      notifSubject = `INTERVIEW: ${email.company_name || 'Unknown'} - ${email.role_title || 'Unknown Role'}`;
      notifBody = `<html><body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
<h2 style="color: #2563eb;">Interview Invitation</h2>
<table style="width: 100%; border-collapse: collapse;">
<tr><td style="padding: 8px; font-weight: bold;">Company:</td><td style="padding: 8px;">${email.company_name || 'Not specified'}</td></tr>
<tr><td style="padding: 8px; font-weight: bold;">Role:</td><td style="padding: 8px;">${email.role_title || 'Not specified'}</td></tr>
<tr><td style="padding: 8px; font-weight: bold;">Date:</td><td style="padding: 8px; font-family: monospace;">${email.interview_date || 'TBC'}</td></tr>
<tr><td style="padding: 8px; font-weight: bold;">Time:</td><td style="padding: 8px; font-family: monospace;">${email.interview_time || 'TBC'}</td></tr>
<tr><td style="padding: 8px; font-weight: bold;">Format:</td><td style="padding: 8px;">${email.interview_format || 'Not specified'}</td></tr>
${email.interview_platform ? `<tr><td style="padding: 8px; font-weight: bold;">Platform:</td><td style="padding: 8px;">${email.interview_platform}</td></tr>` : ''}
${email.interview_location ? `<tr><td style="padding: 8px; font-weight: bold;">Location:</td><td style="padding: 8px;">${email.interview_location}</td></tr>` : ''}
${email.interview_link ? `<tr><td style="padding: 8px; font-weight: bold;">Link:</td><td style="padding: 8px;"><a href="${email.interview_link}">${email.interview_link}</a></td></tr>` : ''}
${email.interviewer_name ? `<tr><td style="padding: 8px; font-weight: bold;">Interviewer:</td><td style="padding: 8px;">${email.interviewer_name}</td></tr>` : ''}
${email.next_steps ? `<tr><td style="padding: 8px; font-weight: bold;">Next Steps:</td><td style="padding: 8px;">${email.next_steps}</td></tr>` : ''}
</table>
<br/>
<a href="${gmailLink}" style="display: inline-block; background: #2563eb; color: white; padding: 12px 24px; text-decoration: none; border-radius: 6px;">View in Gmail</a>
<br/><br/>
<p style="color: #6b7280; font-size: 12px;">Sent by Selvi Job App Email Management System</p>
</body></html>`;
      break;

    case 'offer':
      notifType = 'offer_alert';
      notifSubject = `OFFER: ${email.company_name || 'Unknown'} - ${email.role_title || 'Unknown Role'}`;
      notifBody = `<html><body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
<h2 style="color: #16a34a;">Job Offer Received!</h2>
<table style="width: 100%; border-collapse: collapse;">
<tr><td style="padding: 8px; font-weight: bold;">Company:</td><td style="padding: 8px;">${email.company_name || 'Not specified'}</td></tr>
<tr><td style="padding: 8px; font-weight: bold;">Role:</td><td style="padding: 8px;">${email.role_title || 'Not specified'}</td></tr>
${email.salary_offered ? `<tr><td style="padding: 8px; font-weight: bold;">Salary:</td><td style="padding: 8px; font-family: monospace;">GBP ${email.salary_offered.toLocaleString()}</td></tr>` : ''}
${email.salary_details ? `<tr><td style="padding: 8px; font-weight: bold;">Details:</td><td style="padding: 8px;">${email.salary_details}</td></tr>` : ''}
${email.start_date ? `<tr><td style="padding: 8px; font-weight: bold;">Start Date:</td><td style="padding: 8px;">${email.start_date}</td></tr>` : ''}
${email.response_deadline ? `<tr><td style="padding: 8px; font-weight: bold;">Response By:</td><td style="padding: 8px; color: #dc2626; font-weight: bold;">${email.response_deadline}</td></tr>` : ''}
${email.next_steps ? `<tr><td style="padding: 8px; font-weight: bold;">Next Steps:</td><td style="padding: 8px;">${email.next_steps}</td></tr>` : ''}
</table>
<br/>
<a href="${gmailLink}" style="display: inline-block; background: #16a34a; color: white; padding: 12px 24px; text-decoration: none; border-radius: 6px;">View in Gmail</a>
<br/><br/>
<p style="color: #6b7280; font-size: 12px;">Sent by Selvi Job App Email Management System</p>
</body></html>`;
      break;

    case 'follow_up_request':
      notifType = 'follow_up_alert';
      notifSubject = `ACTION NEEDED: ${email.company_name || 'Unknown'} - ${email.action_required || 'Follow-up required'}`;
      notifBody = `<html><body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
<h2 style="color: #ea580c;">Follow-Up Action Required</h2>
<table style="width: 100%; border-collapse: collapse;">
<tr><td style="padding: 8px; font-weight: bold;">Company:</td><td style="padding: 8px;">${email.company_name || 'Not specified'}</td></tr>
<tr><td style="padding: 8px; font-weight: bold;">Role:</td><td style="padding: 8px;">${email.role_title || 'Not specified'}</td></tr>
<tr><td style="padding: 8px; font-weight: bold;">Action:</td><td style="padding: 8px; font-weight: bold;">${email.action_required || 'See email'}</td></tr>
${email.action_deadline ? `<tr><td style="padding: 8px; font-weight: bold;">Deadline:</td><td style="padding: 8px; color: #dc2626; font-weight: bold; font-family: monospace;">${email.action_deadline}</td></tr>` : ''}
${email.next_steps ? `<tr><td style="padding: 8px; font-weight: bold;">Next Steps:</td><td style="padding: 8px;">${email.next_steps}</td></tr>` : ''}
</table>
<br/>
<a href="${gmailLink}" style="display: inline-block; background: #ea580c; color: white; padding: 12px 24px; text-decoration: none; border-radius: 6px;">View in Gmail</a>
<br/><br/>
<p style="color: #6b7280; font-size: 12px;">Sent by Selvi Job App Email Management System</p>
</body></html>`;
      break;
  }

  if (notifSubject) {
    results.push({
      json: {
        ...email,
        notification_type: notifType,
        notification_subject: notifSubject,
        notification_body: notifBody,
        gmail_link: gmailLink
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { skip: true } }];
}

return results;
